ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/airport#>
PREFIX p: <http://ambrosia.example.org/airport/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE attachment {
  high: { SELECT DISTINCT ?o0 WHERE {
  {
    ?assistant a :Assistant .
    ?unaccompaniedminor a :UnaccompaniedMinor .
    ?unaccompaniedminor p:hasAssistant ?assistant .
    ?passenger a :Passengers .
    ?unaccompaniedminor p:hasPassenger ?passenger .
    ?passenger p:name ?fullname .
    ?assistant p:name ?name_f .
    FILTER(STR(?name_f) = "Clare Allen")
    BIND(?fullname AS ?o0)
  }
  UNION
  {
    ?assistant a :Assistant .
    ?disabledpassenger a :DisabledPassenger .
    ?disabledpassenger p:hasAssistant ?assistant .
    ?passenger a :Passengers .
    ?disabledpassenger p:hasPassenger ?passenger .
    ?passenger p:name ?fullname .
    ?assistant p:name ?name_f .
    FILTER(STR(?name_f) = "Clare Allen")
    BIND(?fullname AS ?o0)
  }
} }
  low: { SELECT DISTINCT ?o0 WHERE {
  {
    ?assistant a :Assistant .
    ?unaccompaniedminor a :UnaccompaniedMinor .
    ?unaccompaniedminor p:hasAssistant ?assistant .
    ?passenger a :Passengers .
    ?unaccompaniedminor p:hasPassenger ?passenger .
    ?passenger p:name ?fullname .
    BIND(?fullname AS ?o0)
  }
  UNION
  {
    ?assistant a :Assistant .
    ?disabledpassenger a :DisabledPassenger .
    ?disabledpassenger p:hasAssistant ?assistant .
    ?passenger a :Passengers .
    ?disabledpassenger p:hasPassenger ?passenger .
    ?passenger p:name ?fullname .
    ?assistant p:name ?name_f .
    FILTER(STR(?name_f) = "Clare Allen")
    BIND(?fullname AS ?o0)
  }
} }
}
